// Build Slack message from ClickHouse summary
const summaryData = $('Query ClickHouse Summary').first().json;
const breachData = $('Query Active Breaches').first().json;

const rows = summaryData?.data || [];
const breaches = breachData?.data || [];

const today = new Date().toISOString().split('T')[0];

// Group by date
const byDate = {};
for (const row of rows) {
  const d = row.recon_date || 'unknown';
  if (!byDate[d]) byDate[d] = {};
  byDate[d][row.status] = { count: row.count, discrepancy: row.total_discrepancy };
}

// Build summary text
let lines = [`*Daily Recon Report* — ${today}`];
lines.push('```');
lines.push('Date       | MATCHED | DISCREPANCY | PENDING');
lines.push('-----------+---------+-------------+--------');

const dates = Object.keys(byDate).sort().reverse().slice(0, 7);
for (const d of dates) {
  const m = byDate[d].MATCHED?.count || 0;
  const disc = byDate[d].DISCREPANCY?.count || 0;
  const pend = byDate[d].PENDING?.count || 0;
  lines.push(`${d} | ${String(m).padStart(7)} | ${String(disc).padStart(11)} | ${String(pend).padStart(7)}`);
}
lines.push('```');

if (breaches.length > 0) {
  lines.push(`\n:rotating_light: *Active Breaches (last 7 days): ${breaches.length}*`);
  for (const b of breaches.slice(0, 5)) {
    lines.push(`  • ${b.account_id} — £${b.discrepancy} — ${b.days_outstanding} days outstanding`);
  }
} else {
  lines.push('\n:white_check_mark: No active breaches in last 7 days');
}

return [{ json: { message: lines.join('\n') } }];
